const input = $input.first().json;

const execution = input.execution || {};
const workflowInfo = input.workflow || {};
const executionError = execution.error || input.trigger || {};
const customData = execution.customData || {};

const correlationId = customData.correlation_id || input.correlation_id || null;
const patientPhone = customData.patient_phone || input.patient_phone || null;
const channel = customData.channel || input.channel || null;

const errorMessage = executionError.message || input.errorMessage || 'Unknown error';
const stackTrace = executionError.stack || null;
const nodeName = execution.lastNodeExecuted || (input.node && input.node.name) || 'unknown';
const workflowName = workflowInfo.name || 'unknown';
const executionId = execution.id || 'unknown';
const timestamp = new Date().toISOString();

return [{
  json: {
    timestamp,
    correlation_id: correlationId,
    workflow: workflowName,
    node: nodeName,
    patient_phone: patientPhone,
    channel,
    error_message: errorMessage,
    stack_trace: stackTrace,
    execution_id: executionId,
    raw_error: JSON.stringify(input)
  }
}];

const item = $input.first().json;
const message = (item.error_message || '').toString();

const recoverablePatterns = [
  /\b429\b/,
  /rate limit/i,
  /timeout/i,
  /timed out/i,
  /ETIMEDOUT/,
  /ECONNRESET/,
  /ECONNREFUSED/,
  /EAI_AGAIN/,
  /temporarily unavailable/i,
  /service unavailable/i,
  /\b502\b/,
  /\b503\b/,
  /\b504\b/
];

const nonRecoverablePatterns = [
  /bad workflow contract/i,
  /missing required field/i,
  /json parsing/i,
  /unexpected token/i,
  /validation error/i,
  /logic error/i,
  /invalid value/i
];

let recoverable = false;
if (nonRecoverablePatterns.some((p) => p.test(message))) {
  recoverable = false;
} else if (recoverablePatterns.some((p) => p.test(message))) {
  recoverable = true;
}

let errorType = 'unclassified';
if (/\b429\b/.test(message) || /rate limit/i.test(message)) errorType = 'rate_limit';
else if (/timeout|timed out|ETIMEDOUT/i.test(message)) errorType = 'timeout';
else if (/50[234]/.test(message) || /unavailable/i.test(message)) errorType = 'temporary_api_outage';
else if (/bad workflow contract/i.test(message)) errorType = 'contract_violation';
else if (/missing required field/i.test(message)) errorType = 'missing_field';
else if (/json parsing|unexpected token/i.test(message)) errorType = 'parsing_error';
else if (/logic error/i.test(message)) errorType = 'logic_error';

return [{
  json: {
    ...item,
    recoverable,
    error_type: errorType
  }
}];

const item = $('Classify Recoverability').first().json;

return [{
  json: {
    success: false,
    recoverable: item.recoverable,
    error: item.error_message,
    workflow: item.workflow,
    node: item.node,
    correlation_id: item.correlation_id,
    timestamp: item.timestamp
  }
}];
